def has_object_permission(self, request, view, obj):

        assert isinstance(obj, CedarMetadataRecord), 'obj must be a CedarMetadataRecord'
        auth = get_user_auth(request)

        permission_source = obj.guid.referent
        if isinstance(permission_source, BaseFileNode):
            permission_source = permission_source.target
        elif not isinstance(permission_source, (Node, Registration)):
            return False

        if request.method in permissions.SAFE_METHODS:
            if not obj.is_published:
                return permission_source.can_edit(auth)
            return permission_source.is_public or permission_source.can_view(auth)
        return permission_source.can_edit(auth)

def perform_destroy(self, instance):
        if instance.state == CollectionSubmissionStates.ACCEPTED:
            instance.remove(
                user=self.request.user,
                comment='Implicit removal via deletion',
                force=True,
            )
        elif instance.state == CollectionSubmissionStates.PENDING:
            instance.reject(
                user=self.request.user,
                comment='Implicit rejection via deletion',
                force=True,
            )
        elif instance.state in [CollectionSubmissionStates.REMOVED, CollectionSubmissionStates.REJECTED]:
            raise ValidationError(f'Resource {instance} is already removed')

def get_object(self):
        comment = self.get_comment()
        comment_node = None

        if isinstance(comment.target.referent, AbstractNode):
            comment_node = comment.target.referent
        elif isinstance(comment.target.referent, BaseFileNode):
            comment_node = comment.target.referent.target
        elif isinstance(comment.target.referent, WikiPage):
            comment_node = comment.target.referent.node
        if comment_node and comment_node.is_registration:
            self.serializer_class = RegistrationCommentDetailSerializer

        return comment

def has_permission(self, request, view):
        if request.method != 'POST':
            return True

        provider_id = request.data.get('provider')

        if not provider_id:
            try:
                provider = RegistrationProvider.get_default()
            except RegistrationProvider.DoesNotExist:
                return True
        else:
            try:
                provider = RegistrationProvider.objects.get(_id=provider_id)
            except RegistrationProvider.DoesNotExist:
                # Let existing validation handle bad provider ids.
                return True

        if not provider.allow_submissions:
            raise Conflict(f"Registry {provider.name} is closed for new submissions. Please start a new registration with a different registry.")

        return True

def perform_destroy(self, instance):
        data = self.request.data['data']
        user = self.request.user
        ids = [datum['id'] for datum in data]
        registrations = []
        for id_ in ids:
            registration = Registration.load(id_)
            if not registration.has_permission(user, osf_permissions.WRITE):
                raise exceptions.PermissionDenied(detail=f'Write permission on registration {id_} required')
            registrations.append(registration)

        for registration in registrations:
            registration.remove_affiliated_institution(inst=instance['self'], user=user)
            registration.save()

def has_object_permission(self, request, view, obj):
        from api.nodes.views import NodeStorageProvider
        if isinstance(obj, BaseAddonSettings):
            obj = obj.owner
        if isinstance(obj, NodeStorageProvider):
            obj = obj.node
        if isinstance(obj, DraftNode):
            obj = obj.registered_draft.first()
        if isinstance(obj, dict):
            obj = obj.get('self', None)
        assert_resource_type(obj, self.acceptable_models)
        auth = get_user_auth(request)

        if request.method in permissions.SAFE_METHODS:
            return obj.is_public or obj.can_view(auth)
        else:
            return obj.can_edit(auth)

def get_default_queryset(self):
        resource = self.get_resource()
        path = self.kwargs[self.path_lookup_url_kwarg]
        provider = self.kwargs[self.provider_lookup_url_kwarg]
        folder_object = self.get_file_object(resource, path, provider)

        # Addon provided files/folders don't have versions so for there date modified we check the history. The history
        # is updated every time we query the file metadata via Waterbutler.
        if provider == 'osfstorage':
            return folder_object.children.prefetch_related(
                'versions',
                'tags',
                'guids',
            )
        else:
            return self.bulk_get_file_nodes_from_wb_resp(folder_object)

def __init__(self, detail=None, code=None):
        if detail is None:
            detail = self.default_detail
        if code is None:
            code = self.default_code

        # For validation failures, we may collect many errors together,
        # so the details should always be coerced to a list if not already.
        if isinstance(detail, tuple):
            detail = list(detail)
        elif not isinstance(detail, dict) and not isinstance(detail, list):
            detail = [detail]

        self.detail = _get_error_details(detail, code)

def used(self):
        if not self.pk:
            return 0
        try:
            # try use fields from objects_used_free manager
            return (self.user_count or 0) + (self.baseobject_count or 0)
        except AttributeError:
            base_objects_qs = self.base_objects.through.objects.filter(licence=self)
            users_qs = self.users.through.objects.filter(licence=self)

            def get_sum(qs):
                return qs.aggregate(sum=Sum("quantity"))["sum"] or 0

            return sum(map(get_sum, [base_objects_qs, users_qs]))

def _confirm_token_scope(resource, required_permission):
    auth_header = request.headers.get('Authorization')
    if not (auth_header and auth_header.startswith('Bearer ')):
        return  # No token, no scope conflict

    if required_permission == permissions.READ:
        if resource.can_view_files(auth=None):
            return  # Always allow read actions for public files/valid VOL
        required_scope = resource.file_read_scope
    else:
        required_scope = resource.file_write_scope

    if required_scope not in _get_token_scopes_from_cas(auth_header):
        raise HTTPError(
            http_status.HTTP_403_FORBIDDEN, 'Provided token has insufficient scope for this action'
        )

def _verify_scopes(self, request, view, token):
        # Anything calling this method should handle the case where
        # `token is None` before making this call.

        required_scopes = self._get_scopes(request, view)

        # Scopes are returned as a space-delimited list in the token
        allowed_scopes = token.attributes['accessTokenScope']
        try:
            normalized_scopes = oauth_scopes.normalize_scopes(allowed_scopes)
        except KeyError:
            # This should never fire: it implies that CAS issued a scope name not in the master list of scopes
            raise exceptions.APIException(
                'OAuth2 token specifies unrecognized scope. User token specifies '
                'the following scopes: {}'.format(', '.join(allowed_scopes)),
            )

        return required_scopes.issubset(normalized_scopes)

def process_name(node, user):
    # If a registered user has a family and given name, use those
    if user.is_registered and user.family_name and user.given_name:
        return {
            'family_name': user.family_name,
            'suffix': user.suffix,
            'given_name': user.given_name,
            'middle_names': user.middle_names,
        }
    elif user.is_registered or user.is_disabled:
        name = user.fullname
    else:
        name = user.get_unclaimed_record(node._id)['name']

    # If the user doesn't autofill his family and given name
    parsed = utils.impute_names(name)
    return {
        'family_name': parsed['family'],
        'suffix': parsed['suffix'],
        'given_name': parsed['given'],
        'middle_names': parsed['middle'],
    }

def get_redirect_url(self, **kwargs):
        guid_str, version_number = Guid.split_guid(kwargs['guids'])
        guid = Guid.load(guid_str)
        if not guid:
            return None
        referent = guid.referent
        if version_number and isinstance(referent, VersionedGuidMixin):
            # if the guid string contains a version number and referent is versionable
            return referent.get_versioned_absolute_api_v2_url(version_number)
        else:
            # if the guid string doesn't have a version number or the referent is not versionable
            if getattr(referent, 'absolute_api_v2_url', None):
                return referent.absolute_api_v2_url
            else:
                raise EndpointNotImplementedError()

def update_institutions(resource, new_institutions, user, post=False):
    add, remove = get_institutions_to_add_remove(
        institutions=resource.affiliated_institutions,
        new_institutions=new_institutions,
    )

    if not post:
        for inst in remove:
            if not user.is_affiliated_with_institution(inst) and not resource.has_permission(user, osf_permissions.ADMIN):
                raise exceptions.PermissionDenied(detail=f'User needs to be affiliated with {inst.name}')
            resource.remove_affiliated_institution(inst, user)

    for inst in add:
        if not user.is_affiliated_with_institution(inst):
            raise exceptions.PermissionDenied(detail=f'User needs to be affiliated with {inst.name}')
        resource.add_affiliated_institution(inst, user)

super().__init__(*args, **kwargs)

    def get_request(self):
        try:
            return self.parent.request
        except AttributeError:
            return None

    def get_queryset(self, request):
        queryset = self.queryset

        if callable(queryset):
            return queryset(request)
        return queryset

    @property
    def field(self):
        request = self.get_request()
        queryset = self.get_queryset(request)

        if queryset is not None:
            self.extra["queryset"] = queryset

        return super().field

def save(self, *args, **kwargs):
        # if you save barcode as empty string (instead of None) you could have
        # only one asset with empty barcode (because of `unique` constraint)
        # if you save barcode as None you could have many assets with empty
        # barcode (becasue `unique` constrainst is skipped)
        for unique_field in ["barcode", "sn"]:
            value = getattr(self, unique_field, None)
            if value == "":
                value = None
            setattr(self, unique_field, value)

        if not self.buyout_date:
            self.buyout_date = self.calculate_buyout_date()
        return super(Asset, self).save(*args, **kwargs)

def _get_host_data(instance):
    from ralph.assets.api.serializers_dchosts import (
        DCHostPhysicalSerializer,
        DCHostSerializer,
    )
    from ralph.data_center.models import DataCenterAsset

    if isinstance(instance, DataCenterAsset):
        serializer = DCHostPhysicalSerializer(instance=instance)
    else:
        serializer = DCHostSerializer(instance=instance)
    if hasattr(serializer.instance, "_previous_state"):
        data = deepcopy(serializer.data)
        data["_previous_state"] = {
            k: v
            for k, v in serializer.instance._previous_state.items()
            if k in serializer.instance.previous_dc_host_update_fields
        }
    else:
        data = serializer.data
    return data

def update_from_record(self, result):
        for value in result:
            domain = checking_type(value)
            try:
                service_dns = value["service"]["name"]
            except TypeError:
                continue
            try:
                service_env = ServiceEnvironment.objects.get(
                    service__name=service_dns, environment__name="prod"
                )
            except ServiceEnvironment.DoesNotExist:
                self.stderr.write(
                    "Service with name {} and prod environment does not exist".format(
                        service_dns
                    )
                )
            else:
                ssl_certificates_object_update(domain, service_env)

def _get_value(self, context, editable=True, **kwargs):
        renderer = ContentRenderer(context['request'])
        placeholder = kwargs.get('placeholder')
        if not placeholder:
            return ''
        if isinstance(placeholder, str):
            placeholder = Placeholder.objects.get(slot=placeholder)
        content = renderer.render_placeholder(
            placeholder=placeholder,
            context=context,
            language=kwargs.get('language'),
            editable=editable,
            use_cache=False,
            width=kwargs.get('width'),
        )
        return strip_tags(content).replace('\n', '').replace('\t', '')

def create_connection_slice_for_sync_webhook_control_context(
    iterable, info: "ResolveInfo", args, connection_type, allow_sync_webhooks
):
    edges_with_context = []
    sliced_connection = create_connection_slice(iterable, info, args, connection_type)

    for edge in sliced_connection.edges:
        node = edge.node
        edge.node = SyncWebhookControlContext(
            node=node, allow_sync_webhooks=allow_sync_webhooks
        )
        edges_with_context.append(edge)
    sliced_connection.edges = edges_with_context
    return sliced_connection

def get_url(self, obj, view_name, request, format):
        if hasattr(obj, "pk") and obj.pk is None:
            return None

        lookup_value = getattr(obj, self.lookup_field)
        kwargs = {
            self.lookup_url_kwarg: lookup_value,
            # add additional related model pk - this is id of the current object
            # (in context)
            self.related_model_lookup_field: obj.object_id,
        }
        return self.reverse(
            # view_name is different for every model (usually
            # <modelname>-customfield-list or <modelname>-customfield-detail)
            view_name,
            kwargs=kwargs,
            request=request,
            format=format,
        )

def create_page_structure(self, page, slot='Main Content'):
        from cms.api import add_plugin
        from cms.utils.i18n import get_public_languages

        placeholder = page.placeholders.get(slot=slot)
        language = get_public_languages()[0]
        glossary = {
            'breakpoints': ['xs', 'sm', 'md', 'lg', 'xl'],
            'fluid': None,
        }
        container = add_plugin(placeholder, 'BootstrapContainerPlugin', language, glossary=glossary)
        row = add_plugin(placeholder, 'BootstrapRowPlugin', language, target=container)
        glossary = {
            'xs-column-width': 'col',
        }
        return add_plugin(placeholder, 'BootstrapColumnPlugin', language, target=row, glossary=glossary)

def patch_jinja_render():
    orig_render = JinjaTemplate.render

    @functools.wraps(orig_render)
    def wrapped_render(self, context=None, request=None):
        # This patching of render only instruments the rendering
        # of the immediate template. It won't include the parent template(s).
        self.name = self.template.name
        template_rendered.send(
            sender=self, template=self, context=make_context(context, request)
        )
        return orig_render(self, context, request)

    if JinjaTemplate.render != wrapped_render:
        JinjaTemplate.original_render = JinjaTemplate.render
        JinjaTemplate.render = wrapped_render

def register_objects(self, typ, *args):
        self.ensure_middleware_installed()
        for arg in args:
            ident = self.get_identifier()
            objects = self.objects
            if objects is None:
                # This can happen if the SilkyMiddleware.process_request is not
                # called for whatever reason. Perhaps if another piece of
                # middleware is not playing ball.
                self._raise_not_configured(
                    'Attempt to register object of type %s without initialisation. '
                )
            if typ not in objects:
                self.objects[typ] = {}
            self.objects[typ][ident] = arg

def get_brand(self):
        brand_id = self.kwargs[self.brand_lookup_url_kwarg]

        # This conditional intended to be temporary until we can address issues that are causing brand_id to be
        # stringified IRL but not in the test app. Remove this comment if test app does no longer gives false positive
        # for this function when registration provider with `.brand is None` is embedded or issue is conclusively fixed.
        if self.kwargs.get('is_embedded') and brand_id == 'None':
            raise NotFound

        try:
            inst = Brand.objects.get(id=int(brand_id))
        except ObjectDoesNotExist:
            raise NotFound

        return inst

def fill_u_list(objects, height_of_device=lambda obj: 1):
            for obj in objects:
                # if position is None when objects simply does not have
                # (assigned) position and position 0 is for some
                # accessories (pdu) with left-right orientation and
                # should not be included in free/filled space.
                if obj[0] == 0 or obj[0] is None:
                    continue

                start = obj[0] - 1
                end = min(self.max_u_height, obj[0] + int(height_of_device(obj)) - 1)
                height = end - start
                if height:
                    u_list[start:end] = [False] * height
